reallocate(index, currentSize, newSize) {
  if (index + currentSize > this.size || index + newSize > this.size) {
    return false;
  }

  if (newSize === currentSize) {
    return true;
  }

  if (newSize < currentSize) {
    this.memory.fill(0, index + newSize, index + currentSize);
    return true;
  }

  const neededSpace = newSize - currentSize;
  const nextIndex = index + currentSize;
  let hasSpace = true;

  for (let i = nextIndex; i < nextIndex + neededSpace; i++) {
    if (this.memory[i] !== 0) {
      hasSpace = false;
      break;
    }
  }

  if (hasSpace) {
    this.memory.fill(1, index, index + newSize);
    return true;
  }

  return false;
}
