```java
class BrightnessFilter implements ImageFilter {
    private int brightnessLevel;

    public BrightnessFilter(int brightnessLevel) {
        this.brightnessLevel = brightnessLevel;
    }

    public BufferedImage filter(BufferedImage sourceImage) {
        BufferedImage result = new BufferedImage(sourceImage.getWidth(), sourceImage.getHeight(), sourceImage.getType());
        for (int y = 0; y < sourceImage.getHeight(); y++) {
            for (int x = 0; x < sourceImage.getWidth(); x++) {
                int rgb = sourceImage.getRGB(x, y);
                int r = (rgb >> 16) & 0xFF;
                int g = (rgb >> 8) & 0xFF;
                int b = rgb & 0xFF;

                r = Math.max(0, Math.min(255, r + brightnessLevel));
                g = Math.max(0, Math.min(255, g + brightnessLevel));
                b = Math.max(0, Math.min(255, b + brightnessLevel));

                int adjustedRGB = (r << 16) | (g << 8) | b;
                result.setRGB(x, y, adjustedRGB);
            }
        }
        return result;
    }
}
