// Financial computation library: finance_calculator.cpp
#include <iostream>
#include <vector>
#include <cmath>

class FinanceCalculator {
public:
    static double calculate_average(const std::vector<double>& data) {
        double sum = 0.0;
        for (auto& value : data) {
            sum += value;
        }
        return data.empty() ? 0.0 : (sum / data.size());
    }

    static double calculate_total(const std::vector<double>& data) {
        double total = 0.0;
        for (auto& value : data) {
            total += value;
        }
        return total;
    }

    static double calculate_standard_deviation(const std::vector<double>& data) {
        if (data.empty()) return 0.0;
        double mean = calculate_average(data);
        double sum_squared_diff = 0.0;
        for (auto& value : data) {
            sum_squared_diff += (value - mean) * (value - mean);
        }
        return sqrt(sum_squared_diff / data.size());
    }
};

