        Self { edges: std::collections::HashMap::new() }
    }

    fn add_edge(&mut self, src: i32, dst: i32) {
        self.edges.entry(src).or_insert(vec![]).push(dst);
    }

    fn get_neighbors(&self, node: &i32) -> Vec<&i32> {
        match self.edges.get(node) {
            Some(neighbors) => neighbors.iter().collect(),
            None => vec![],
        }
    }

