        let visited = self.depth_first_search(start);
        let unique_visited: HashSet<_> = visited.iter().cloned().collect();
        let total_nodes = visited.len();
        let unique_nodes = unique_visited.len();

        let mut result = std::collections::HashMap::new();
        result.insert("visited_nodes".to_string(), total_nodes);
        result.insert("total_nodes".to_string(), total_nodes);
        result.insert("unique_nodes".to_string(), unique_nodes);

        result
    }
